import{_ as o,c as n,o as r,ah as s}from"./chunks/framework.DwHsq7Fg.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/o-auth-2.md","filePath":"basics_api/o-auth-2.md"}'),i={name:"basics_api/o-auth-2.md"};function l(e,t,g,a,p,u){return r(),n("div",null,t[0]||(t[0]=[s('<h3 id="🛡️-oauth-2-open-authorization-2-0-стандарт-авторизаціі-для-безпечного-доступу" tabindex="-1">🛡️ OAuth 2 (Open Authorization 2.0): Стандарт авторизації для безпечного доступу <a class="header-anchor" href="#🛡️-oauth-2-open-authorization-2-0-стандарт-авторизаціі-для-безпечного-доступу" aria-label="Permalink to “🛡️ OAuth 2 (Open Authorization 2.0): Стандарт авторизації для безпечного доступу”">​</a></h3><p><strong>Що це?</strong></p><p>OAuth 2 - це <strong>протокол авторизації</strong>, який дозволяє стороннім додаткам отримувати <strong>обмежений доступ</strong> до ресурсів користувача на іншому сервісі <strong>без розкриття облікових даних користувача</strong> (наприклад, логіна та пароля). Це фундаментальний стандарт для побудови безпечних інтеграцій між різними веб-сервісами та додатками.</p><p><strong>Основні ролі в OAuth 2:</strong></p><ul><li><strong>Resource Owner (Власник ресурсу):</strong> Користувач, чиї дані або ресурси потребує сторонній додаток (наприклад, ви).</li><li><strong>Client (Клієнт):</strong> Сторонній додаток, який хоче отримати доступ до ресурсів власника ресурсу (наприклад, програма для редагування фотографій, яка хоче отримати доступ до ваших фотографій у хмарному сховищі).</li><li><strong>Authorization Server (Сервер авторизації):</strong> Сервер, який видає <strong>токени доступу</strong> клієнту після успішної аутентифікації власника ресурсу та отримання його згоди.</li><li><strong>Resource Server (Сервер ресурсів):</strong> Сервер, який зберігає ресурси власника ресурсу та перевіряє отримані токени доступу перед наданням доступу клієнту.</li></ul><p><strong>Основні концепції:</strong></p><ul><li><strong>Токени доступу (Access Tokens):</strong> Рядки символів, які клієнт використовує для здійснення запитів до сервера ресурсів від імені власника ресурсу. Токени доступу зазвичай мають обмежений термін дії.</li><li><strong>Токени оновлення (Refresh Tokens):</strong> Довгоживучі токени, які клієнт може використовувати для отримання нових токенів доступу без повторної взаємодії з власником ресурсу (за певних умов).</li><li><strong>Сфери (Scopes):</strong> Визначають рівень доступу, який клієнт запитує до ресурсів власника ресурсу (наприклад, лише читання профілю, редагування фотографій). Власник ресурсу може надати або відхилити певні сфери доступу.</li><li><strong>Гранти (Grants):</strong> Різні способи отримання токенів доступу, залежно від типу клієнта та сценарію використання.</li></ul><p><strong>Основні типи грантів (Grant Types):</strong></p><ul><li><p><strong>Authorization Code Grant (Код авторизації):</strong> Найбільш безпечний та поширений тип гранту для веб-додатків. Включає перенаправлення користувача на сервер авторизації для надання згоди, а потім обмін отриманого коду авторизації на токен доступу.</p><ol><li>Клієнт перенаправляє користувача на сервер авторизації (<code>/authorize</code> endpoint) з ідентифікатором клієнта, URL перенаправлення, бажаними сферами та типом відповіді (<code>code</code>).</li><li>Користувач аутентифікується на сервері авторизації та надає згоду клієнту на доступ до своїх ресурсів у межах запитаних сфер.</li><li>Сервер авторизації перенаправляє користувача назад на вказаний клієнтом URL перенаправлення з кодом авторизації.</li><li>Клієнт відправляє код авторизації, свій ідентифікатор та секрет (якщо є) на сервер авторизації (<code>/token</code> endpoint) для обміну на токен доступу та, можливо, токен оновлення.</li><li>Сервер авторизації валідує код та облікові дані клієнта і повертає токени.</li><li>Клієнт використовує токен доступу для здійснення запитів до сервера ресурсів (<code>/api/users/me</code> endpoint).</li></ol></li><li><p><strong>Implicit Grant (Неявний грант):</strong> (Зазвичай не рекомендується через безпекові міркування, особливо для додатків, що можуть використовувати Authorization Code Grant з PKCE) Використовувався для односторінкових додатків (SPA). Токен доступу повертається безпосередньо через URL-фрагмент після надання згоди.</p></li><li><p><strong>Password Grant (Грант за паролем):</strong> Клієнт безпосередньо передає облікові дані користувача (логін та пароль) на сервер авторизації. Використовується рідко і лише для дуже довірених клієнтів (наприклад, власні мобільні додатки сервісу).</p></li><li><p><strong>Client Credentials Grant (Грант за обліковими даними клієнта):</strong> Використовується для авторизації між серверами, коли клієнт діє від свого імені (не від імені користувача). Клієнт надає свій ідентифікатор та секрет безпосередньо на сервер авторизації для отримання токена доступу.</p></li><li><p><strong>Refresh Token Grant (Грант за токеном оновлення):</strong> Клієнт використовує отриманий раніше токен оновлення для запиту нового токена доступу без повторної взаємодії з користувачем.</p></li></ul><p><strong>Переваги OAuth 2:</strong></p><ul><li><strong>Безпека:</strong> Користувачі не розкривають свої облікові дані стороннім додаткам.</li><li><strong>Обмежений доступ:</strong> Користувач може надавати клієнту лише певні права доступу (сфери).</li><li><strong>Відкликання доступу:</strong> Користувач може в будь-який момент відкликати доступ, наданий клієнту.</li><li><strong>Стандартизація:</strong> Широко прийнятий стандарт, що забезпечує сумісність між різними сервісами та додатками.</li><li><strong>Делегування авторизації:</strong> Дозволяє одному сервісу отримувати доступ до ресурсів іншого сервісу від імені користувача.</li></ul><p><strong>Недоліки OAuth 2:</strong></p><ul><li><strong>Складність:</strong> Реалізація може бути складнішою порівняно з простими методами аутентифікації (наприклад, API Keys).</li><li><strong>Кілька кроків:</strong> Процес отримання токена доступу може включати кілька перенаправлень та обмінів.</li></ul><p><strong>Використання OAuth 2:</strong></p><p>OAuth 2 є основою для багатьох сучасних веб- та мобільних додатків, включаючи:</p><ul><li>&quot;Увійти через Google&quot;, &quot;Підключити до Facebook&quot; та інші механізми соціального входу.</li><li>Дозволи для сторонніх додатків на доступ до даних користувача (наприклад, доступ програми для редагування фотографій до фотографій у хмарному сховищі).</li><li>Авторизація між мікросервісами.</li></ul><p><strong>Висновок:</strong></p><p>OAuth 2 є потужним та безпечним стандартом авторизації, який дозволяє стороннім додаткам отримувати обмежений доступ до ресурсів користувача без розкриття їхніх облікових даних. Розуміння різних типів грантів та ролей в OAuth 2 є важливим для розробки безпечних та інтегрованих веб-сервісів та додатків.</p>',18)]))}const d=o(i,[["render",l]]);export{h as __pageData,d as default};
